function report = generateLocalRasterTextureDataset(options)
%GENERATELOCALRASTERTEXTUREDATASET Render ignored 1k raster-texture pairs.
%
% The first two TIFFs directly under test_data/ supply texture. Their three
% bands are summed before normalization, retaining up to 766 source levels
% for 8-bit RGB. All outputs are written below test_data/generated/ and are
% therefore excluded from Git. Geometry uses one-based [x,y]=[column,row]
% image centers, local ENU [X,Y,Z] metres, and SYNTHETIC_LOCAL_Z elevation.
%
% Six scenes use both source TIFFs: target-relief along- and cross-track
% planes, exact along- and cross-track height steps, a smooth radial
% normalized-sinc surface, and a gently curved hillside with four sparse
% vertical-walled buildings.
% Raster texture is sampled bilinearly in world coordinates; the two detector
% images are still rendered independently through their pinhole cameras.
%
% Traceability: algorithm description Secs. 2.1, 10.2, 10.5, 11.2, and
% 14.1; Eqs. (52)-(58) and Algorithm 1 inputs/truth diagnostics.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [1024, 1024]
    options.ReliefMetres (1, 1) double ...
        {mustBeFinite, mustBePositive} = 50
    options.CenterGsdMetres (1, 1) double ...
        {mustBeFinite, mustBePositive} = 0.5
    options.TextureMetresPerPixel (1, 1) double ...
        {mustBeFinite, mustBePositive} = 0.4
    options.Supersample (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 2
    options.DatasetName (1, 1) string ...
        {mustBeDatasetName} = "raster_texture_50m_v1"
    options.WriteFiles (1, 1) logical = true
    options.Overwrite (1, 1) logical = false
    options.Display (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
src = fullfile(root, "src");
oldPath = path;
addpath(src);
cleanup = onCleanup(@() path(oldPath));

dataDir = fullfile(root, "test_data");
outDir = fullfile(dataDir, "generated", options.DatasetName);
files = dir(fullfile(dataDir, "*.tif"));
if numel(files) < 2
    error("generateLocalRasterTextureDataset:MissingSourceImages", ...
        "At least two TIFF files are required directly under test_data/.");
end
[~, order] = sort(string({files.name}));
files = files(order(1:2));

if options.WriteFiles
    if isfolder(outDir) && ~options.Overwrite
        error("generateLocalRasterTextureDataset:OutputExists", ...
            "Output exists. Use Overwrite=true or a new DatasetName: %s", ...
            outDir);
    end
    if ~isfolder(outDir)
        mkdir(outDir);
    end
end

defs = sceneDefinitions(options.ReliefMetres);
scenes = cell(1, numel(defs));
rows = cell(numel(defs), 10);
totalTimer = tic;

for k = 1:numel(defs)
    d = defs(k);
    sourcePath = fullfile(files(d.SourceIndex).folder, ...
        files(d.SourceIndex).name);
    [texture, source] = loadTexture(sourcePath, d, ...
        options.TextureMetresPerPixel);
    if d.SurfaceType == "plane"
        slope = fitSlope(options.ImageSize, options.CenterGsdMetres, ...
            d.MeanObliquityDegrees, d.ConvergenceDegrees, ...
            d.LookAzimuthDegrees, d.SlopeDirection, options.ReliefMetres);
    else
        slope = 0;
    end
    renderer = createRenderer(d, options, slope);

    timer = tic;
    pair = renderer.renderPairWithTexture(texture);
    renderSeconds = toc(timer);
    timer = tic;
    truth = sceneTruth(renderer, pair);
    truthSeconds = toc(timer);
    metrics = sceneMetrics(renderer, pair, truth, source, ...
        renderSeconds, truthSeconds);
    sceneDir = fullfile(outDir, d.Name);
    manifest = sceneManifest(d, renderer, texture, source, metrics);

    if options.WriteFiles
        writeScene(sceneDir, pair, truth, manifest, options.Overwrite);
    end

    scenes{k} = struct( ...
        "Name", d.Name, ...
        "SourceFile", string(files(d.SourceIndex).name), ...
        "SourcePreview", source.Preview, ...
        "Renderer", renderer, ...
        "Pair", pair, ...
        "Truth", truth, ...
        "Metrics", metrics, ...
        "Manifest", manifest, ...
        "OutputDirectory", string(sceneDir));
    rows(k, :) = {d.Name, string(files(d.SourceIndex).name), ...
        renderer.SurfaceType, metrics.HeightMinimumMetres, ...
        metrics.HeightMaximumMetres, metrics.HeightReliefMetres, ...
        metrics.ReferenceValidFraction, ...
        metrics.CorrespondenceValidFraction, ...
        renderSeconds, truthSeconds};

    fprintf("  %s: %s, height [%.3f, %.3f] m (%.3f m relief), " + ...
        "reference valid %.3f, correspondence valid %.3f, %.2f s\n", ...
        d.Name, files(d.SourceIndex).name, ...
        metrics.HeightMinimumMetres, metrics.HeightMaximumMetres, ...
        metrics.HeightReliefMetres, metrics.ReferenceValidFraction, ...
        metrics.CorrespondenceValidFraction, ...
        renderSeconds + truthSeconds);
end

results = table(string(rows(:, 1)), string(rows(:, 2)), ...
    string(rows(:, 3)), cell2mat(rows(:, 4)), cell2mat(rows(:, 5)), ...
    cell2mat(rows(:, 6)), cell2mat(rows(:, 7)), cell2mat(rows(:, 8)), ...
    cell2mat(rows(:, 9)), cell2mat(rows(:, 10)), VariableNames=[ ...
    "Scene", "SourceFile", "SurfaceType", "MinimumHeightMetres", ...
    "MaximumHeightMetres", "ReliefMetres", "ReferenceValidFraction", ...
    "CorrespondenceValidFraction", "RenderSeconds", "TruthSeconds"]);
sceneArray = [scenes{:}];
report = struct( ...
    "DatasetName", options.DatasetName, ...
    "OutputDirectory", string(outDir), ...
    "ImageSize", options.ImageSize, ...
    "ReliefTargetMetres", options.ReliefMetres, ...
    "BandAggregation", "uint16(R)+uint16(G)+uint16(B)", ...
    "SourceNormalization", "divide by three times source class maximum", ...
    "Scenes", sceneArray, ...
    "Results", results, ...
    "RuntimeSeconds", toc(totalTimer), ...
    "Figures", struct.empty, ...
    "PixelConvention", "one-based [x,y]=[column,row] centers", ...
    "WorldFrame", "local ENU [X,Y,Z] metres", ...
    "VerticalDatum", "SYNTHETIC_LOCAL_Z", ...
    "Interpolation", "bilinear raster texture; supersampled detector render");

if options.WriteFiles
    writePairPreview(outDir, report.Scenes);
    writeHeightPreview(outDir, report.Scenes);
    summary = struct( ...
        "datasetName", report.DatasetName, ...
        "imageSize", report.ImageSize, ...
        "reliefTargetMetres", report.ReliefTargetMetres, ...
        "bandAggregation", report.BandAggregation, ...
        "sourceNormalization", report.SourceNormalization, ...
        "pixelConvention", report.PixelConvention, ...
        "worldFrame", report.WorldFrame, ...
        "verticalDatum", report.VerticalDatum, ...
        "interpolation", report.Interpolation, ...
        "runtimeSeconds", report.RuntimeSeconds, ...
        "scenes", [sceneArray.Manifest]);
    writeJson(fullfile(outDir, "dataset_manifest.json"), summary);
end

fprintf("Local raster-texture dataset: %d scenes at %d x %d\n", ...
    height(results), options.ImageSize(1), options.ImageSize(2));
fprintf("  RGB aggregation: uint16(R)+uint16(G)+uint16(B)\n");
fprintf("  Output: %s\n", outDir);
disp(results);

if options.Display
    report.Figures = displayDataset(report);
end

clear cleanup
end

function d = sceneDefinitions(relief)
d = repmat(struct( ...
    "Name", "", "SourceIndex", 1, "SurfaceType", "plane", ...
    "SlopeDirection", "along-track", "StepDirection", "along-track", ...
    "TextureRotationDegrees", 0, "TextureCenterFraction", [0.5, 0.5], ...
    "MeanObliquityDegrees", 55, "ConvergenceDegrees", 1, ...
    "LookAzimuthDegrees", 90, "BaseHeightMetres", 0, ...
    "StepHeightMetres", 0, "SincAmplitudeMetres", 60, ...
    "SincLobeSpacingMetres", 110, "SincCenterENU", [0, 0], ...
    "TerrainAlongSlopeDegrees", 0, "TerrainCrossSlopeDegrees", 0, ...
    "TerrainCurvaturePerMetre", 0, "CurvatureCenterENU", [0, 0], ...
    "Buildings", zeros(0, 5)), 1, 6);
d(1).Name = "source10_along_slope";
d(1).SourceIndex = 1;
d(1).SlopeDirection = "along-track";
d(1).TextureRotationDegrees = -12;
d(1).TextureCenterFraction = [0.50, 0.50];
d(1).MeanObliquityDegrees = 55;
d(1).ConvergenceDegrees = 1;
d(1).LookAzimuthDegrees = 90;

d(2).Name = "source102_cross_slope";
d(2).SourceIndex = 2;
d(2).SlopeDirection = "cross-track";
d(2).TextureRotationDegrees = 18;
d(2).TextureCenterFraction = [0.50, 0.50];
d(2).MeanObliquityDegrees = 65;
d(2).ConvergenceDegrees = 2;
d(2).LookAzimuthDegrees = 35;

d(3).Name = "source10_along_step";
d(3).SourceIndex = 1;
d(3).SurfaceType = "step";
d(3).StepDirection = "along-track";
d(3).TextureRotationDegrees = 31;
d(3).TextureCenterFraction = [0.49, 0.51];
d(3).MeanObliquityDegrees = 55;
d(3).ConvergenceDegrees = 1;
d(3).LookAzimuthDegrees = 90;
d(3).BaseHeightMetres = 0;
d(3).StepHeightMetres = relief;

d(4).Name = "source102_cross_step";
d(4).SourceIndex = 2;
d(4).SurfaceType = "step";
d(4).StepDirection = "cross-track";
d(4).TextureRotationDegrees = -24;
d(4).TextureCenterFraction = [0.51, 0.49];
d(4).MeanObliquityDegrees = 65;
d(4).ConvergenceDegrees = 2;
d(4).LookAzimuthDegrees = 35;
d(4).BaseHeightMetres = 0;
d(4).StepHeightMetres = relief;

d(5).Name = "source102_radial_sinc";
d(5).SourceIndex = 2;
d(5).SurfaceType = "radial-sinc";
d(5).TextureRotationDegrees = 7;
d(5).TextureCenterFraction = [0.52, 0.48];
d(5).MeanObliquityDegrees = 50;
d(5).ConvergenceDegrees = 1.5;
d(5).LookAzimuthDegrees = 125;
d(5).BaseHeightMetres = 0;
d(5).SincAmplitudeMetres = 60;
d(5).SincLobeSpacingMetres = 110;
d(5).SincCenterENU = [0, 0];

d(6).Name = "source10_curved_hillside_buildings";
d(6).SourceIndex = 1;
d(6).SurfaceType = "hillside-buildings";
d(6).TextureRotationDegrees = -9;
d(6).TextureCenterFraction = [0.50, 0.50];
d(6).MeanObliquityDegrees = 60;
d(6).ConvergenceDegrees = 2;
d(6).LookAzimuthDegrees = 110;
d(6).BaseHeightMetres = 0;
d(6).TerrainAlongSlopeDegrees = 8;
d(6).TerrainCrossSlopeDegrees = 2;
d(6).TerrainCurvaturePerMetre = 3e-5;
d(6).CurvatureCenterENU = [0, 0];
% [centerE,centerN,widthE,depthN,height], all metres. Equal footprint
% dimensions and height keep the structures approximately cubic.
d(6).Buildings = [ ...
    -125, -95, 24, 24, 24; ...
    -45, 80, 28, 28, 28; ...
    60, -40, 20, 20, 20; ...
    135, 95, 26, 26, 26];
end

function [texture, source] = loadTexture(path, d, metresPerPixel)
rgb = imread(path);
if ndims(rgb) ~= 3 || size(rgb, 3) < 3
    error("generateLocalRasterTextureDataset:SourceMustBeRgb", ...
        "Source TIFF must contain at least three bands: %s", path);
end
if ~isa(rgb, "uint8")
    error("generateLocalRasterTextureDataset:SourceMustBeUint8", ...
        "Source TIFF must use the expected 8-bit sample class: %s", path);
end
maximum = 3 * double(intmax(class(rgb)));
sumImage = uint16(rgb(:, :, 1)) + uint16(rgb(:, :, 2)) ...
    + uint16(rgb(:, :, 3));
v = double(sumImage) ./ maximum;
center = [1 + d.TextureCenterFraction(1) * (size(v, 2) - 1), ...
    1 + d.TextureCenterFraction(2) * (size(v, 1) - 1)];
texture = RasterSurfaceTexture(v, ...
    MetresPerPixel=metresPerPixel, CenterPixelXY=center, ...
    RotationDegrees=d.TextureRotationDegrees, ...
    Identifier=d.Name + "_rgb_sum");
step = max(1, ceil(max(size(v)) / 900));
[~, name, extension] = fileparts(path);
source = struct( ...
    "Path", string(path), ...
    "FileName", string(name) + string(extension), ...
    "ImageSize", size(v), ...
    "InputClass", string(class(rgb)), ...
    "MaximumBandSum", maximum, ...
    "UniqueBandSumLevels", ...
    nnz(histcounts(sumImage, -0.5:(maximum + 0.5))), ...
    "MinimumBandSum", min(sumImage, [], "all"), ...
    "MaximumObservedBandSum", max(sumImage, [], "all"), ...
    "Preview", uint16(sumImage(1:step:end, 1:step:end)));
end

function slopeDegrees = fitSlope(imageSize, gsd, obliquity, ...
        convergence, azimuth, directionName, relief)
base = SyntheticPinholeRenderer("slope-fit", imageSize, ...
    CenterGsdMetres=gsd, MeanObliquityDegrees=obliquity, ...
    ConvergenceDegrees=convergence, LookAzimuthDegrees=azimuth, ...
    Supersample=1, PsfSigmaPixels=0);
p = [1, 1; imageSize(2), 1; 1, imageSize(1); ...
    imageSize(2), imageSize(1)];
h = [sind(azimuth), cosd(azimuth)];
c = [cosd(azimuth), -sind(azimuth)];
if directionName == "along-track"
    direction = h;
else
    direction = c;
end
[world, valid] = base.ReferenceCamera.imageToWorldAtHeight(p, 0);
u = world(valid, 1:2) * direction.';
slope0 = relief / (max(u) - min(u));
lo = 0;
hi = max(tand(20), 2 .* slope0);
for k = 1:40
    slope = (lo + hi) / 2;
    actual = surfaceRelief(base.ReferenceCamera, p, slope .* direction);
    if actual < relief
        lo = slope;
    else
        hi = slope;
    end
end
slopeDegrees = atand((lo + hi) / 2);
end

function relief = surfaceRelief(camera, p, slopeENU)
[z, ~, ~, valid] = PinholePlaneOracle.surfaceHeight( ...
    camera, p, 0, slopeENU);
relief = max(z(valid)) - min(z(valid));
end

function renderer = createRenderer(d, options, slope)
searchRange = [-options.ReliefMetres, options.ReliefMetres];
if d.SurfaceType == "radial-sinc"
    searchRange = [min(-options.ReliefMetres, ...
        d.BaseHeightMetres - 0.25 .* d.SincAmplitudeMetres), ...
        max(options.ReliefMetres, ...
        d.BaseHeightMetres + d.SincAmplitudeMetres + 10)];
elseif d.SurfaceType == "hillside-buildings"
    searchRange = [-2 .* options.ReliefMetres, ...
        2 .* options.ReliefMetres + max(d.Buildings(:, 5))];
end
common = { ...
    "CenterGsdMetres", options.CenterGsdMetres, ...
    "MeanObliquityDegrees", d.MeanObliquityDegrees, ...
    "ConvergenceDegrees", d.ConvergenceDegrees, ...
    "LookAzimuthDegrees", d.LookAzimuthDegrees, ...
    "SearchRangeMetres", searchRange, ...
    "Supersample", options.Supersample, ...
    "PsfSigmaPixels", 0.55, "BitDepth", 10};
if d.SurfaceType == "step"
    renderer = SyntheticPinholeRenderer(d.Name, options.ImageSize, ...
        common{:}, SurfaceType="step", ...
        TrueHeightMetres=d.BaseHeightMetres, ...
        StepHeightMetres=d.StepHeightMetres, ...
        StepDirection=d.StepDirection);
elseif d.SurfaceType == "radial-sinc"
    renderer = SyntheticPinholeRenderer(d.Name, options.ImageSize, ...
        common{:}, SurfaceType="radial-sinc", ...
        TrueHeightMetres=d.BaseHeightMetres, ...
        SincAmplitudeMetres=d.SincAmplitudeMetres, ...
        SincLobeSpacingMetres=d.SincLobeSpacingMetres, ...
        SincCenterENU=d.SincCenterENU);
    peakPixel = round([(options.ImageSize(2) + 1) / 2, ...
        (options.ImageSize(1) + 1) / 2]);
    [peakWorld, valid] = renderer.ReferenceCamera.imageToWorldAtHeight( ...
        peakPixel, d.BaseHeightMetres + d.SincAmplitudeMetres);
    if ~valid
        error("generateLocalRasterTextureDataset:InvalidSincCenter", ...
            "The radial-sinc peak pixel does not reach the peak height.");
    end
    renderer = SyntheticPinholeRenderer(d.Name, options.ImageSize, ...
        common{:}, SurfaceType="radial-sinc", ...
        TrueHeightMetres=d.BaseHeightMetres, ...
        SincAmplitudeMetres=d.SincAmplitudeMetres, ...
        SincLobeSpacingMetres=d.SincLobeSpacingMetres, ...
        SincCenterENU=peakWorld(1:2));
elseif d.SurfaceType == "hillside-buildings"
    renderer = SyntheticPinholeRenderer(d.Name, options.ImageSize, ...
        common{:}, SurfaceType="hillside-buildings", ...
        TrueHeightMetres=d.BaseHeightMetres, ...
        AlongTrackSlopeDegrees=d.TerrainAlongSlopeDegrees, ...
        CrossTrackSlopeDegrees=d.TerrainCrossSlopeDegrees, ...
        TerrainCurvaturePerMetre=d.TerrainCurvaturePerMetre, ...
        CurvatureCenterENU=d.CurvatureCenterENU, ...
        Buildings=d.Buildings);
elseif d.SlopeDirection == "along-track"
    renderer = SyntheticPinholeRenderer(d.Name, options.ImageSize, ...
        common{:}, AlongTrackSlopeDegrees=slope);
else
    renderer = SyntheticPinholeRenderer(d.Name, options.ImageSize, ...
        common{:}, CrossTrackSlopeDegrees=slope);
end
end

function truth = sceneTruth(renderer, pair)
[y, x] = ndgrid(1:renderer.ImageSize(1), 1:renderer.ImageSize(2));
p = [x(:), y(:)];
if renderer.SurfaceType == "step"
    [~, z, vr] = PinholeStepOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [w, vg, inside, visible] = PinholeStepOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.StepHeightMetres, ...
        renderer.StepDirectionENU, ...
        PositionMetres=renderer.StepPositionMetres);
    vc = vr & vg & inside & visible;
elseif renderer.SurfaceType == "radial-sinc"
    [~, z, vr] = PinholeSincOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SincAmplitudeMetres, renderer.SincLobeSpacingMetres, ...
        CenterENU=renderer.SincCenterENU);
    [w, vg, inside, visible] = PinholeSincOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SincAmplitudeMetres, ...
        renderer.SincLobeSpacingMetres, ...
        CenterENU=renderer.SincCenterENU);
    vc = vr & vg & inside & visible;
elseif renderer.SurfaceType == "hillside-buildings"
    [~, z, vr] = PinholeHillsideBuildingsOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU, renderer.TerrainCurvaturePerMetre, ...
        renderer.Buildings, ...
        CurvatureCenterENU=renderer.CurvatureCenterENU);
    [w, vg, inside, visible] = ...
        PinholeHillsideBuildingsOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU, ...
        renderer.TerrainCurvaturePerMetre, renderer.Buildings, ...
        CurvatureCenterENU=renderer.CurvatureCenterENU);
    vc = vr & vg & inside & visible;
else
    [z, ~, ~, vr] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [w, vg, inside] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    vc = vr & vg & inside;
end
vr = vr & pair.ReferenceValid(:);
movingSupport = interp2(double(pair.MovingValid), w(:, 1), w(:, 2), ...
    "linear", 0) >= 1 - 64 * eps;
vc = vc & vr & movingSupport;
geom = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
[t, kappa, vk] = geom.heightDerivative(p, z, DeltaHeight=0.5);
vk = vk & vr;
z(~vr) = NaN;
w(~vc, :) = NaN;
t(~vk, :) = NaN;
kappa(~vk) = NaN;
truth = struct( ...
    "HeightMetres", reshape(z, renderer.ImageSize), ...
    "CorrespondenceXY", reshape(w, [renderer.ImageSize, 2]), ...
    "DisplacementX", reshape(w(:, 1) - p(:, 1), renderer.ImageSize), ...
    "DisplacementY", reshape(w(:, 2) - p(:, 2), renderer.ImageSize), ...
    "HeightDerivativeXY", reshape(t, [renderer.ImageSize, 2]), ...
    "ObservabilityPixelsPerMetre", reshape(kappa, renderer.ImageSize), ...
    "ReferenceSurfaceValid", reshape(vr, renderer.ImageSize), ...
    "CorrespondenceValid", reshape(vc, renderer.ImageSize));
end

function m = sceneMetrics(renderer, pair, truth, source, renderTime, truthTime)
z = truth.HeightMetres(truth.ReferenceSurfaceValid);
m = struct( ...
    "ImageRows", renderer.ImageSize(1), ...
    "ImageColumns", renderer.ImageSize(2), ...
    "BitDepth", renderer.BitDepth, ...
    "HeightMinimumMetres", min(z), ...
    "HeightMaximumMetres", max(z), ...
    "HeightReliefMetres", max(z) - min(z), ...
    "MedianObservabilityPixelsPerMetre", ...
    median(truth.ObservabilityPixelsPerMetre, "all", "omitmissing"), ...
    "ReferenceValidFraction", nnz(pair.ReferenceValid) / numel(pair.ReferenceValid), ...
    "MovingValidFraction", nnz(pair.MovingValid) / numel(pair.MovingValid), ...
    "CorrespondenceValidFraction", ...
    nnz(truth.CorrespondenceValid) / numel(truth.CorrespondenceValid), ...
    "SourceUniqueBandSumLevels", source.UniqueBandSumLevels, ...
    "SourceMaximumBandSum", source.MaximumBandSum, ...
    "SourceMaximumObservedBandSum", source.MaximumObservedBandSum, ...
    "RenderSeconds", renderTime, ...
    "TruthSeconds", truthTime);
end

function m = sceneManifest(d, renderer, texture, source, metrics)
m = struct( ...
    "identifier", d.Name, ...
    "sourceFile", source.FileName, ...
    "sourceImageSize", source.ImageSize, ...
    "sourceClass", source.InputClass, ...
    "bandAggregation", "uint16(R)+uint16(G)+uint16(B)", ...
    "maximumBandSum", source.MaximumBandSum, ...
    "uniqueObservedBandSumLevels", source.UniqueBandSumLevels, ...
    "textureMetresPerPixel", texture.MetresPerPixel, ...
    "textureCenterPixelXY", texture.CenterPixelXY, ...
    "textureRotationDegrees", texture.RotationDegrees, ...
    "imageSize", renderer.ImageSize, ...
    "outputBitDepth", renderer.BitDepth, ...
    "horizontalFieldOfViewDegrees", ...
    renderer.HorizontalFieldOfViewDegrees, ...
    "centerGsdMetres", renderer.CenterGsdMetres, ...
    "meanObliquityDegrees", renderer.MeanObliquityDegrees, ...
    "convergenceDegrees", renderer.ConvergenceDegrees, ...
    "lookAzimuthDegrees", renderer.LookAzimuthDegrees, ...
    "referenceRollDegrees", renderer.ReferenceRollDegrees, ...
    "movingRollDegrees", renderer.MovingRollDegrees, ...
    "surfaceType", renderer.SurfaceType, ...
    "trueHeightMetres", renderer.TrueHeightMetres, ...
    "surfaceSlopeENU", renderer.SurfaceSlopeENU, ...
    "stepHeightMetres", renderer.StepHeightMetres, ...
    "stepDirection", renderer.StepDirection, ...
    "stepPositionMetres", renderer.StepPositionMetres, ...
    "sincAmplitudeMetres", renderer.SincAmplitudeMetres, ...
    "sincLobeSpacingMetres", renderer.SincLobeSpacingMetres, ...
    "sincCenterENU", renderer.SincCenterENU, ...
    "terrainCurvaturePerMetre", renderer.TerrainCurvaturePerMetre, ...
    "curvatureCenterENU", renderer.CurvatureCenterENU, ...
    "buildings", renderer.Buildings, ...
    "searchRangeMetres", renderer.SearchRangeMetres, ...
    "targetMotionPerLabelPixels", ...
    renderer.TargetMotionPerLabelPixels, ...
    "supersample", renderer.Supersample, ...
    "psfSigmaPixels", renderer.PsfSigmaPixels, ...
    "heightMinimumMetres", metrics.HeightMinimumMetres, ...
    "heightMaximumMetres", metrics.HeightMaximumMetres, ...
    "heightReliefMetres", metrics.HeightReliefMetres, ...
    "medianObservabilityPixelsPerMetre", ...
    metrics.MedianObservabilityPixelsPerMetre, ...
    "referenceValidFraction", metrics.ReferenceValidFraction, ...
    "movingValidFraction", metrics.MovingValidFraction, ...
    "correspondenceValidFraction", metrics.CorrespondenceValidFraction, ...
    "pixelConvention", "one-based [x,y]=[column,row] centers", ...
    "worldFrame", "local ENU [X,Y,Z] metres", ...
    "verticalDatum", "SYNTHETIC_LOCAL_Z", ...
    "textureInterpolation", "bilinear", ...
    "detectorInterpolation", "supersampled Gaussian PSF and block average");
end

function writeScene(sceneDir, pair, truth, manifest, overwrite)
if isfolder(sceneDir) && ~overwrite
    error("generateLocalRasterTextureDataset:SceneOutputExists", ...
        "Scene output exists: %s", sceneDir);
end
if ~isfolder(sceneDir)
    mkdir(sceneDir);
end
imwrite(pair.ReferenceImage, fullfile(sceneDir, "reference.tif"), ...
    Compression="lzw");
imwrite(pair.MovingImage, fullfile(sceneDir, "moving.tif"), ...
    Compression="lzw");
referenceValid = pair.ReferenceValid;
movingValid = pair.MovingValid;
heightMetres = truth.HeightMetres;
correspondenceXY = truth.CorrespondenceXY;
displacementX = truth.DisplacementX;
displacementY = truth.DisplacementY;
heightDerivativeXY = truth.HeightDerivativeXY;
observabilityPixelsPerMetre = truth.ObservabilityPixelsPerMetre;
referenceSurfaceValid = truth.ReferenceSurfaceValid;
correspondenceValid = truth.CorrespondenceValid;
save(fullfile(sceneDir, "truth.mat"), "referenceValid", "movingValid", ...
    "heightMetres", "correspondenceXY", "displacementX", ...
    "displacementY", "heightDerivativeXY", ...
    "observabilityPixelsPerMetre", "referenceSurfaceValid", ...
    "correspondenceValid");
writeJson(fullfile(sceneDir, "manifest.json"), manifest);
end

function writeJson(path, value)
writelines(string(jsonencode(value, PrettyPrint=true)), path);
end

function writePairPreview(outDir, scenes)
n = numel(scenes);
h = size(scenes(1).Pair.ReferenceImage, 1);
w = size(scenes(1).Pair.ReferenceImage, 2);
tile = zeros(n * h, 2 * w, "uint16");
for k = 1:n
    rows = (k - 1) * h + (1:h);
    tile(rows, 1:w) = scenes(k).Pair.ReferenceImage;
    tile(rows, w + (1:w)) = scenes(k).Pair.MovingImage;
end
imwrite(uint8(round(255 .* double(tile) ./ 1023)), ...
    fullfile(outDir, "pair_preview.png"));
end

function writeHeightPreview(outDir, scenes)
n = numel(scenes);
h = size(scenes(1).Truth.HeightMetres, 1);
w = size(scenes(1).Truth.HeightMetres, 2);
columns = 2;
rows = ceil(n / columns);
tile = zeros(rows * h, columns * w, 3);
map = turbo(256);
zlim = datasetHeightLimits(scenes);
for k = 1:n
    z = scenes(k).Truth.HeightMetres;
    valid = scenes(k).Truth.ReferenceSurfaceValid & isfinite(z);
    q = (z - zlim(1)) ./ (zlim(2) - zlim(1));
    q(~valid) = 0;
    index = 1 + round(255 .* min(max(q, 0), 1));
    rgb = reshape(map(index(:), :), h, w, 3);
    rgb(repmat(~valid, 1, 1, 3)) = 0;
    row = floor((k - 1) / columns);
    col = mod(k - 1, columns);
    tile(row * h + (1:h), col * w + (1:w), :) = rgb;
end
imwrite(uint8(round(255 .* tile)), ...
    fullfile(outDir, "height_preview.png"));
end

function figs = displayDataset(report)
n = numel(report.Scenes);
srcFig = uifigure(Name="Private summed-RGB source textures", ...
    Position=[80, 80, 1300, 650]);
srcGrid = uigridlayout(srcFig, [1, 2]);
for k = 1:2
    scene = report.Scenes(k);
    v = viewer2d(srcGrid);
    title(v, "Summed RGB source: " + scene.SourceFile);
    imageshow(scene.SourcePreview, Parent=v, DisplayRangeMode="data-range");
end

images = cell(1, 2 * n);
for k = 1:n
    images{2 * k - 1} = report.Scenes(k).Pair.ReferenceImage;
    images{2 * k} = report.Scenes(k).Pair.MovingImage;
end
pairFig = uifigure(Name="Raster-texture synthetic reference/moving pairs", ...
    Position=[110, 70, 1450, 900]);
pairGrid = uigridlayout(pairFig, [1, 1]);
pairViewer = viewer2d(pairGrid);
title(pairViewer, "Rows: scenes 1-" + n + "; columns: reference, moving");
imageshow(imtile(cat(4, images{:}), GridSize=[n, 2]), ...
    Parent=pairViewer, DisplayRangeMode="10-bit");

heightFig = figure(Name="Raster-texture height truth", ...
    Position=[140, 80, 1450, 850], Color=[0.08, 0.08, 0.08]);
layout = tiledlayout(heightFig, ceil(n / 2), 2, TileSpacing="compact", ...
    Padding="compact");
fg = [0.9, 0.9, 0.9];
zlim = datasetHeightLimits(report.Scenes);
for k = 1:n
    ax = nexttile(layout);
    z = report.Scenes(k).Truth.HeightMetres;
    imagesc(ax, z, AlphaData=isfinite(z));
    axis(ax, "image");
    cb = colorbar(ax);
    cb.Color = fg;
    clim(ax, zlim);
    set(ax, Color=[0.08, 0.08, 0.08], XColor=fg, YColor=fg);
    title(ax, report.Scenes(k).Name, Interpreter="none");
    ax.Title.Color = fg;
    xlabel(ax, "x / column (pixel)");
    ylabel(ax, "y / row (pixel)");
end
colormap(heightFig, turbo);
heading = title(layout, "Truth elevation Z (m), SYNTHETIC_LOCAL_Z");
heading.Color = fg;

diagnosticFig = figure(Name="Raster-texture geometry diagnostics", ...
    Position=[170, 60, 1500, 900], Color=[0.08, 0.08, 0.08]);
layout = tiledlayout(diagnosticFig, n, 2, TileSpacing="compact", ...
    Padding="compact");
for k = 1:n
    scene = report.Scenes(k);
    ax = nexttile(layout);
    imagesc(ax, hypot(scene.Truth.DisplacementX, ...
        scene.Truth.DisplacementY), ...
        AlphaData=scene.Truth.CorrespondenceValid);
    axis(ax, "image");
    cb = colorbar(ax);
    cb.Color = fg;
    set(ax, Color=[0.08, 0.08, 0.08], XColor=fg, YColor=fg);
    title(ax, scene.Name + " displacement (pixels)", Interpreter="none");
    ax.Title.Color = fg;
    ax = nexttile(layout);
    imagesc(ax, scene.Truth.ObservabilityPixelsPerMetre, ...
        AlphaData=isfinite(scene.Truth.ObservabilityPixelsPerMetre));
    axis(ax, "image");
    cb = colorbar(ax);
    cb.Color = fg;
    set(ax, Color=[0.08, 0.08, 0.08], XColor=fg, YColor=fg);
    title(ax, scene.Name + " ||dw/dZ|| (pixels/metre)", ...
        Interpreter="none");
    ax.Title.Color = fg;
end
colormap(diagnosticFig, parula);
figs = struct("Sources", srcFig, "Pairs", pairFig, ...
    "HeightTruth", heightFig, "Geometry", diagnosticFig);
end

function limits = datasetHeightLimits(scenes)
lo = inf;
hi = -inf;
for k = 1:numel(scenes)
    z = scenes(k).Truth.HeightMetres;
    valid = scenes(k).Truth.ReferenceSurfaceValid & isfinite(z);
    lo = min(lo, min(z(valid)));
    hi = max(hi, max(z(valid)));
end
if hi <= lo
    limits = lo + [-0.5, 0.5];
else
    limits = [lo, hi];
end
end

function mustBeDatasetName(name)
if strlength(name) == 0 || contains(name, ["/", "\"])
    error("generateLocalRasterTextureDataset:InvalidDatasetName", ...
        "DatasetName must be one nonempty path component.");
end
end
